import (
	context "context"
	fern "github.com/oauth-client-credentials-default/fern"
	fernclient "github.com/oauth-client-credentials-default/fern/client"
	option "github.com/oauth-client-credentials-default/fern/option"
)

client := fernclient.NewClient(
	option.WithToken(
		"<YOUR_AUTH_TOKEN>",
	),
)
response, err := client.Auth.Gettoken(
	context.TODO(),
	&fern.AuthGetTokenRequest{
		ClientID:     "client_id",
		ClientSecret: "client_secret",
		GrantType:    fern.AuthGetTokenRequestGrantTypeClientCredentials,
	},
)
